#include <bits/stdc++.h>
using namespace std;
int a[1005],b[]={0,10,100,1000,10000,100000,1000000,10000000,100000000},n,q;
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
	cin>>n>>q;
	for(int i=1;i<=n;i++) cin>>a[i];
	for(int i=1;i<=q;i++) 
	{
		int num,len,sum=0;
		cin>>len>>num;
		for(int j=1;j<=n;j++)
		{
			if((a[j]%b[len])==num) sum++;
		}
		cout<<sum<<'\n';
	}
	return 0;
 }
